window.addEventListener("DOMContentLoaded",function(){function e(){fetch("cookie-banner.html").then(r=>r.text()).then(t=>{document.getElementById("cookie-banner-container").innerHTML=t;var n=document.createElement("script");n.src="cookie-banner.js",document.body.appendChild(n)})}"requestIdleCallback"in window?requestIdleCallback(e):setTimeout(e,500)});